const webhookData = $('Webhook Trigger').first().json;
const body = webhookData.body || {};
const filter = body.filter || {};
const wantSummary = body.summary === true;

let leads = $input.all().map(item => item.json);

// Handle placeholder response
if (leads.length === 1 && leads[0]._placeholder) {
  return [{ json: leads[0] }];
}

// Apply filters
if (filter.status) {
  leads = leads.filter(l => (l.status || '').toLowerCase() === filter.status.toLowerCase());
}
if (filter.industry) {
  leads = leads.filter(l => (l.industry || '').toLowerCase().includes(filter.industry.toLowerCase()));
}

if (wantSummary) {
  const summary = {
    total: leads.length,
    by_status: {},
    by_industry: {},
    avg_lead_score: 0,
    by_urgency: {}
  };

  let scoreSum = 0;
  for (const lead of leads) {
    const status = lead.status || 'unknown';
    summary.by_status[status] = (summary.by_status[status] || 0) + 1;
    const industry = lead.industry || 'unknown';
    summary.by_industry[industry] = (summary.by_industry[industry] || 0) + 1;
    const urgency = lead.website_urgency || 'unknown';
    summary.by_urgency[urgency] = (summary.by_urgency[urgency] || 0) + 1;
    scoreSum += parseFloat(lead.lead_score) || 0;
  }
  summary.avg_lead_score = leads.length > 0 ? Math.round((scoreSum / leads.length) * 10) / 10 : 0;

  return [{ json: { type: 'summary', ...summary } }];
} else {
  return [{ json: { type: 'leads', total: leads.length, leads } }];
}
